  /// Handles camera capture requests with explicit user interaction.
  Future<void> _handleCameraCapture(String requestId, Map<String, dynamic> payload) async {
    try {
      // Validate payload parameters
      final preferredCamera = payload['camera'] as String? ?? 'back';
      if (!{'front', 'back'}.contains(preferredCamera)) {
        _sendErrorToWeb('INVALID_PARAM', 'Invalid camera parameter', requestId);
        return;
