        _sendResponseToWeb(requestId, 'cameraCaptureResult', {
          'success': false,
          'reason': 'NO_CAMERA_AVAILABLE',
        });
        return;
      }

      final cameraDescription = preferredCamera == 'front'
          ? cameras.firstWhere(
              (c) => c.lensDirection == CameraLensDirection.front,
              orElse: () => cameras.first,
            )
          : cameras.firstWhere(
              (c) => c.lensDirection == CameraLensDirection.back,
              orElse: () => cameras.first,
            );

      final cameraController = CameraController(
        cameraDescription,
        ResolutionPreset.medium,
        enableAudio: false, // Minimize permissions - no audio needed
