  /// Handles push notification token requests.
  Future<void> _handlePushTokenRequest(String requestId) async {
    try {
      final messaging = FirebaseMessaging.instance;

      // Check current permission status
      final settings = await messaging.getNotificationSettings();

      if (settings.authorizationStatus == AuthorizationStatus.notDetermined) {
        // Request permission with minimal capabilities
        final requestResult = await messaging.requestPermission(
          alert: true,
          badge: true,
          sound: true,
          announcement: false,
          carPlay: false,
          criticalAlert: false,
          provisional: false,
