        if (requestResult.authorizationStatus != AuthorizationStatus.authorized) {
          _sendResponseToWeb(requestId, 'pushTokenResult', {
            'success': false,
            'reason': 'PERMISSION_DENIED',
          });
          return;
        }
      } else if (settings.authorizationStatus == AuthorizationStatus.denied) {
        _sendResponseToWeb(requestId, 'pushTokenResult', {
          'success': false,
